import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import API from '../../services/axios';

function ManageEvents() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => { fetchEvents(); }, []);

  const fetchEvents = async () => {
    try {
      const res = await API.get('/events');
      setEvents(res.data.events || []);
    } catch { } finally { setLoading(false); }
  };

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Delete "${name}"? This cannot be undone.`)) return;
    try {
      await API.delete(`/events/${id}`);
      setEvents(events.filter(e => e._id !== id));
    } catch { alert('Failed to delete event'); }
  };

  const CATEGORY_IMAGES = {
    Concert: 'https://images.unsplash.com/photo-1501386761578-eac5c94b800a?w=400&q=80',
    Festival: 'https://images.unsplash.com/photo-1533174072545-7a4b6ad7a6c3?w=400&q=80',
    Sports: 'https://images.unsplash.com/photo-1471295253337-3ceaaedca402?w=400&q=80',
    Workshop: 'https://images.unsplash.com/photo-1552664730-d307ca884978?w=400&q=80',
    Conference: 'https://images.unsplash.com/photo-1540575467063-178a50c2df87?w=400&q=80',
    default: 'https://images.unsplash.com/photo-1470229722913-7c0e2dbbafd3?w=400&q=80',
  };

  if (loading) return (
    <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', minHeight: '100vh', background: '#fdf6f3' }}>
      <div style={{ textAlign: 'center' }}>
        <div style={{ fontSize: '2.5rem', marginBottom: '1rem' }}>🌸</div>
        <p style={{ color: '#c9a99a', fontFamily: "'DM Sans', sans-serif" }}>Loading events...</p>
      </div>
    </div>
  );

  return (
    <div style={{ padding: '2rem', background: '#fdf6f3', minHeight: '100vh', fontFamily: "'DM Sans', sans-serif" }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
        <div>
          <h1 style={{ fontSize: '1.6rem', fontWeight: '700', color: '#2d1f1f', margin: 0, fontFamily: "'Cormorant Garamond', serif" }}>Manage Events</h1>
          <p style={{ color: '#a08880', fontSize: '0.84rem', marginTop: '4px' }}>{events.length} events total</p>
        </div>
        <Link to="/admin/create-event" style={{ background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', padding: '10px 20px', borderRadius: '12px', textDecoration: 'none', fontWeight: '600', fontSize: '0.84rem', boxShadow: '0 4px 14px rgba(201,169,154,0.35)' }}>
          ➕ New Event
        </Link>
      </div>

      {events.length === 0 ? (
        <div style={{ background: 'white', borderRadius: '20px', padding: '5rem', textAlign: 'center', border: '1px solid #f5e8e3' }}>
          <div style={{ fontSize: '3rem', marginBottom: '1rem' }}>📭</div>
          <h2 style={{ color: '#2d1f1f', fontFamily: "'Cormorant Garamond', serif" }}>No Events Yet</h2>
          <Link to="/admin/create-event" style={{ marginTop: '1rem', display: 'inline-block', background: 'linear-gradient(135deg, #c9a99a, #b8887a)', color: 'white', padding: '10px 24px', borderRadius: '12px', textDecoration: 'none', fontWeight: '600' }}>
            Create First Event
          </Link>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(290px, 1fr))', gap: '1.5rem' }}>
          {events.map(event => (
            <div key={event._id} style={{ background: 'white', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 4px 20px rgba(201,169,154,0.1)', border: '1px solid #f5e8e3', transition: 'all 0.3s' }}
              onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-3px)'; e.currentTarget.style.boxShadow = '0 12px 30px rgba(201,169,154,0.2)'; }}
              onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 4px 20px rgba(201,169,154,0.1)'; }}
            >
              <div style={{ position: 'relative', height: '160px', overflow: 'hidden' }}>
                <img src={event.image || CATEGORY_IMAGES[event.category] || CATEGORY_IMAGES.default}
                  alt={event.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }}
                  onError={e => { e.target.src = CATEGORY_IMAGES.default; }} />
                <div style={{ position: 'absolute', inset: 0, background: 'linear-gradient(to top, rgba(45,31,31,0.5) 0%, transparent 60%)' }} />
                <span style={{ position: 'absolute', top: '10px', left: '10px', background: 'rgba(253,246,243,0.93)', color: '#c9a99a', padding: '3px 10px', borderRadius: '20px', fontSize: '0.68rem', fontWeight: '700' }}>{event.category}</span>
                <span style={{ position: 'absolute', top: '10px', right: '10px', background: event.status === 'upcoming' ? 'rgba(58,122,90,0.9)' : 'rgba(160,80,64,0.9)', color: 'white', padding: '3px 10px', borderRadius: '20px', fontSize: '0.68rem', fontWeight: '700' }}>
                  {event.status || 'upcoming'}
                </span>
              </div>

              <div style={{ padding: '1.1rem' }}>
                <h3 style={{ fontWeight: '700', color: '#2d1f1f', marginBottom: '0.5rem', fontSize: '0.96rem' }}>{event.name}</h3>
                <p style={{ color: '#a08880', fontSize: '0.75rem', marginBottom: '0.3rem' }}>📅 {new Date(event.date).toLocaleDateString('en-IN')} • {event.time}</p>
                <p style={{ color: '#a08880', fontSize: '0.75rem', marginBottom: '0.5rem' }}>📍 {event.venue}</p>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
                  <span style={{ color: '#c9a99a', fontWeight: '800', fontSize: '1rem' }}>₹{event.price}</span>
                  <span style={{ color: '#a08880', fontSize: '0.75rem' }}>{event.availableSeats}/{event.totalSeats} seats</span>
                </div>

                <div style={{ display: 'flex', gap: '8px' }}>
                  <button onClick={() => handleDelete(event._id, event.name)} style={{ flex: 1, background: '#fdeee9', color: '#a05040', border: '1px solid #f0c4b8', padding: '8px', borderRadius: '10px', cursor: 'pointer', fontWeight: '600', fontSize: '0.78rem', fontFamily: "'DM Sans', sans-serif" }}>
                    🗑️ Delete
                  </button>
                  <Link to={`/admin/edit-event/${event._id}`} style={{ flex: 1, background: '#fdf6f3', color: '#6b5a55', border: '1px solid #f0ddd7', padding: '8px', borderRadius: '10px', textDecoration: 'none', fontWeight: '600', fontSize: '0.78rem', textAlign: 'center' }}>
                    ✏️ Edit
                  </Link>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
export default ManageEvents;
